24	const shape = createBox(BOX);
25	const bounds = shapeBounds(shape);
26	
27	const PAD = 4;
28	const vx = bounds.minX - PAD;
29	const vy = bounds.minY - PAD;
30	const vw = bounds.maxX - bounds.minX + PAD * 2;
31	const vh = bounds.maxY - bounds.minY + PAD * 2;
32	
33	// Golden-ratio framing. The focal point of the subject — the lissajous center
34	// on the top face — is anchored at the upper-left golden power point:
35	//   x = W · (1 − 1/φ) ≈ W · 0.382
36	//   y = H · (1 − 1/φ) ≈ H · 0.382
37	const PHI_INV_SQ = 0.381_966_011_250_105_1;
