42	const focalIso = project(BOX.x + BOX.w / 2, BOX.y + BOX.h / 2, BOX.z + BOX.d);
43	
44	function isoToCanvas([ix, iy]: Vec2): Vec2 {
45	  return [ANCHOR_X + (ix - focalIso[0]), ANCHOR_Y + (iy - focalIso[1])];
46	}
47	
48	// The four extreme corners of the iso projection:
49	//  • left/right: bottom-square front-left / back-right corners (same y)
50	//  • bottom-most: bottom-square front corner
51	//  • top-most:    top-square back corner
52	const bottomZ = BOX.z;
53	const topZB = BOX.z + BOX.d;
54	const leftCorner = isoToCanvas(project(BOX.x, BOX.y + BOX.h, bottomZ));
55	const rightCorner = isoToCanvas(project(BOX.x + BOX.w, BOX.y, bottomZ));
56	const bottomCorner = isoToCanvas(project(BOX.x + BOX.w, BOX.y + BOX.h, bottomZ));
57	const topCorner = isoToCanvas(project(BOX.x, BOX.y, topZB));
58	
59	// Pixel offset for the box SVG so its focal point lands on the anchor.
60	// SVG top-left in canvas = anchor − (focalIso − viewBox origin).
61	const BOX_LEFT = ANCHOR_X - (focalIso[0] - vx);
62	const BOX_TOP = ANCHOR_Y - (focalIso[1] - vy);
