80	  .map((v, i) => `${i === 0 ? "M" : "L"}${v[0].toFixed(2)},${v[1].toFixed(2)}`)
81	  .join(" ")} Z`;
82	
83	const FACE_FILL: Record<string, string> = {
84	  top: "var(--card)",
85	  front: "var(--card)",
86	  right: "var(--card)",
87	};
