**Action**: New file — a React Server Component that renders the isometric box + Lissajous SVG.

This is a static SVG with all geometry computed at module scope (no client state needed). Key differences from the blog composition:

- **No Remotion imports** — uses `@repo/ui/lib/iso` and `@repo/ui/lib/brand`
- **Golden-ratio mirrored right** — `ANCHOR_X = CANVAS_W * (1 - PHI_INV_SQ)` instead of `CANVAS_W * PHI_INV_SQ`
- **Container styling** — rendered inside a `bg-accent rounded-md` wrapper with `overflow-hidden` (so hairlines clip at rounded corners)
- **Responsive** — the SVG uses `viewBox` with `width="100%" height="100%"` to fill its 16:9 container
- **Face fills** — use `var(--accent)` (matches container bg) so faces blend in. Strokes remain `var(--border)`.

```tsx
import {
  lissajousPoints as computeLissajousPoints,
  LOGO_CURVE,
} from "@repo/ui/lib/brand";
import type { Box3D, Vec2 } from "@repo/ui/lib/iso";
import { createBox, facePath, project, shapeBounds } from "@repo/ui/lib/iso";

const CANVAS_W = 1200;
const CANVAS_H = 675;

const BOX: Box3D = { x: 0, y: 0, z: 0, w: 220, h: 220, d: 22 };
const LISSAJOUS_RADIUS = 76;
const STEPS = 512;

const shape = createBox(BOX);
const bounds = shapeBounds(shape);

const PAD = 4;
const vx = bounds.minX - PAD;
const vy = bounds.minY - PAD;
const vw = bounds.maxX - bounds.minX + PAD * 2;
const vh = bounds.maxY - bounds.minY + PAD * 2;

// Golden-ratio framing — focal point at upper-RIGHT power point
const PHI_INV_SQ = 0.381_966_011_250_105_1;
const ANCHOR_X = CANVAS_W * (1 - PHI_INV_SQ); // ~61.8% from left
const ANCHOR_Y = CANVAS_H * PHI_INV_SQ;        // ~38.2% from top

const focalIso = project(BOX.x + BOX.w / 2, BOX.y + BOX.h / 2, BOX.z + BOX.d);

function isoToCanvas([ix, iy]: Vec2): Vec2 {
  return [ANCHOR_X + (ix - focalIso[0]), ANCHOR_Y + (iy - focalIso[1])];
}

// Extreme projected corners for hairlines
const bottomZ = BOX.z;
const topZB = BOX.z + BOX.d;
const leftCorner = isoToCanvas(project(BOX.x, BOX.y + BOX.h, bottomZ));
const rightCorner = isoToCanvas(project(BOX.x + BOX.w, BOX.y, bottomZ));
const bottomCorner = isoToCanvas(
  project(BOX.x + BOX.w, BOX.y + BOX.h, bottomZ)
);
const topCorner = isoToCanvas(project(BOX.x, BOX.y, topZB));

// Box SVG position
const BOX_LEFT = ANCHOR_X - (focalIso[0] - vx);
const BOX_TOP = ANCHOR_Y - (focalIso[1] - vy);

const topZ = BOX.z + BOX.d;
const cx = BOX.x + BOX.w / 2;
const cy = BOX.y + BOX.h / 2;

const lissajousProjected: Vec2[] = computeLissajousPoints(
  LOGO_CURVE.a,
  LOGO_CURVE.b,
  LOGO_CURVE.delta,
  STEPS,
)
  .slice(0, STEPS)
  .map(([px, py]) =>
    project(cx + LISSAJOUS_RADIUS * px, cy + LISSAJOUS_RADIUS * py, topZ)
  );

const lissajousPath = `${lissajousProjected
  .map(
    (v, i) =>
      `${i === 0 ? "M" : "L"}${v[0].toFixed(2)},${v[1].toFixed(2)}`
  )
  .join(" ")} Z`;

const faces = shape.faces;

export function IsometricHero() {
  return (
    <div className="aspect-video w-full overflow-hidden rounded-md bg-accent">
      <svg
        className="h-full w-full"
        viewBox={`0 0 ${CANVAS_W} ${CANVAS_H}`}
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Hairlines from box corners to canvas edges */}
        <line
          stroke="var(--border)"
          strokeWidth={1}
          x1={0}
          x2={leftCorner[0]}
          y1={leftCorner[1]}
          y2={leftCorner[1]}
        />
        <line
          stroke="var(--border)"
          strokeWidth={1}
          x1={rightCorner[0]}
          x2={CANVAS_W}
          y1={rightCorner[1]}
          y2={rightCorner[1]}
        />
        <line
          stroke="var(--border)"
          strokeWidth={1}
          x1={topCorner[0]}
          x2={topCorner[0]}
          y1={0}
          y2={topCorner[1]}
        />
        <line
          stroke="var(--border)"
          strokeWidth={1}
          x1={bottomCorner[0]}
          x2={bottomCorner[0]}
          y1={bottomCorner[1]}
          y2={CANVAS_H}
        />

        {/* Isometric box faces */}
        <g transform={`translate(${BOX_LEFT - vx}, ${BOX_TOP - vy})`}>
          {faces.map((face, i) => (
            <path
              d={facePath(face)}
              fill="var(--accent)"
              fillRule="evenodd"
              key={`${face.type}-${i}`}
              stroke="var(--border)"
              strokeWidth={1}
            />
          ))}
          {/* Lissajous curve on top face */}
          <path
            d={lissajousPath}
            fill="none"
            stroke="var(--border)"
            strokeWidth={1}
          />
        </g>
      </svg>
    </div>
  );
}
```

**Note on the `<g transform>` approach**: The blog composition uses a nested `<div>` + second `<svg>` to position the box. For the landing page, we use a single SVG with a `<g>` transform instead — simpler, same result. The transform offsets the box group so its viewBox-relative coordinates map correctly to the canvas. This may need slight adjustment during implementation if the box position doesn't line up — the fallback is to replicate the blog's two-SVG approach exactly.

