              <div
                className="absolute left-full h-px w-[100vw]"
                style={{
                  top: `${HAIRLINE_Y_PCT}%`,
                  backgroundColor: "var(--border)",
                }}
              />
              <IsometricHero />
            </div>
          </div>

          {/* Left: Text + CTA — in flow, original positioning */}
          <div className="relative z-20 mx-auto flex min-h-screen w-full max-w-[1400px] items-start px-8 pt-[18vh] pb-24 md:px-16 md:pt-[15vh] md:pb-32 lg:items-end lg:px-24 lg:pt-0 lg:pb-[calc(50vh+3vw+2rem)]">
            <div className="flex w-full max-w-sm flex-col justify-center md:max-w-lg lg:max-w-sm">
              <Icons.logoShort className="mb-4 hidden h-5 w-5 text-muted-foreground md:block" />
              <h1 className="mb-4 font-medium font-pp text-4xl md:text-3xl lg:text-3xl">
